const settingsKey = 'settings';
let backgroundAudio = null;
let backgroundAudioSize = 0;
let backgroundAudioPath = '/static/audio/画音工作室-子鹤.mp3';

let settings = {
    backgroundAudio: 0, // 0 = 关闭, >0 = 开启，范围在0 ~ 1之间
    soundEffectAudio: 0, // 0 = 关闭, >0 = 开启，范围在0 ~ 1之间
    notificationAudio: 0 // 0 = 关闭, >0 = 开启，范围在0 ~ 1之间
}

document.addEventListener('DOMContentLoaded', async function () {
    await loadSettings();
});
document.addEventListener('click', async function () {
    await playBackgroundAudio();
});

async function loadSettings() {
    try {
        const raw = localStorage.getItem(settingsKey);
        if (!raw) return;
        const loadedSettings = JSON.parse(raw);
        settings.backgroundAudio = loadedSettings.backgroundAudio || 0;
        settings.soundEffectAudio = loadedSettings.soundEffectAudio || 0;
        settings.notificationAudio = loadedSettings.notificationAudio || 0;
        return true;
    } catch (error) {
        return false;
    }
}

async function saveSettings() {
    try {
        localStorage.setItem(settingsKey, JSON.stringify(settings));
        return true;
    } catch (error) {
        return false;
    }
}

async function playBackgroundAudio() {
    if (!backgroundAudio) {
        backgroundAudio = document.createElement('audio');
        backgroundAudio.id = 'background-audio';
        backgroundAudio.loop = true;
        backgroundAudio.preload = 'auto';
        backgroundAudio.setAttribute('playsinline', '');
        backgroundAudio.setAttribute('webkit-playsinline', '');
        backgroundAudio.src = encodeURI(backgroundAudioPath);
        document.body.appendChild(backgroundAudio);
        backgroundAudio.load();
    } else {
        if (settings.backgroundAudio > 0) {
            backgroundAudio.volume = settings.backgroundAudio;
            await backgroundAudio.play();
        } else {
            backgroundAudio.pause();
        }
    }
}
